import{_ as a,o as t,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"212. Discretionary Leave Without Pay Royal Children S","description":"","frontmatter":{"title":"212. Discretionary Leave Without Pay Royal Children S","eba":"Mental Health Services 2024-2028","topics":["leave","parental-leave"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/leave/212-discretionary-leave-without-pay-royal-children-s.md","filePath":"ebas/mental-health/management-admin/leave/212-discretionary-leave-without-pay-royal-children-s.md"}'),r={name:"ebas/mental-health/management-admin/leave/212-discretionary-leave-without-pay-royal-children-s.md"};function n(s,e,l,h,c,p){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_212-discretionary-leave-without-pay-royal-children-s" tabindex="-1">212. Discretionary Leave Without Pay Royal Children S <a class="header-anchor" href="#_212-discretionary-leave-without-pay-royal-children-s" aria-label="Permalink to &quot;212. Discretionary Leave Without Pay Royal Children S&quot;">​</a></h1><p>Hospital This clause only applies to Management and Administrative Officers at Royal Children’s Hospital classified under Part 2 of <a href="/eba/ebas/mental-health/schedules/07-management-and-administrative-officers-classifications.html">Schedule 7</a> of this Agreement.</p><p><strong>212.1</strong> Department Heads may grant discretionary leave without pay (DLWOP) up to a maximum of eight (8) weeks. Longer periods of DLWOP up to 52 weeks require the approval of the Divisional Director, and in the case of the Corporate Services Director, Executive Director Corporate.</p><p><strong>212.2</strong> With the exception of the Parental Leave clause DLWOP is granted at the absolute discretion of the Employer.</p><p><strong>212.3</strong> DLWOP will only be considered after all other paid entitlements have been taken.</p><p><strong>212.4</strong> All DLWOP must be applied for and, if appropriate, approved in advance, using the Employer’s standard leave form.</p><p><strong>212.5</strong> Absences on approved leave without pay do not break continuity of service; however, such absences do not count in the calculation of benefits.</p><p><strong>212.6</strong> An Employee will not be paid for any public holidays that may occur whilst on DLWOP.</p>',8)])])}const m=a(r,[["render",n]]);export{y as __pageData,m as default};
